static int handle_delete_note(struct mg_connection* conn, void* cbdata) {
    char note_id_str[32];
    if (!get_param(conn, "note_id", note_id_str, sizeof(note_id_str))) {
        send_json(conn, 400, "Missing note_id", NULL);
        return 200;
    }

    int note_id = atoi(note_id_str);
    int rc = note_delete_note(note_id);
    send_json(conn, rc == 0 ? 200 : 404, rc == 0 ? "Note deleted" : "Note not found", NULL);
    return 200;
}

static const char* get_param(struct mg_connection* conn, const char* name, char* buf, size_t buf_size) {
    const struct mg_request_info* ri = mg_get_request_info(conn);

    // 先尝试从 query_string 获取 (GET 请求)
    if (ri->query_string) {
        int len = mg_get_var(ri->query_string, strlen(ri->query_string), name, buf, buf_size);
        if (len > 0) return buf;
    }

    // 尝试从 POST 数据获取
    // 读取 POST 数据
    char post_data[MAX_POST_DATA];
    int post_len = mg_read(conn, post_data, sizeof(post_data) - 1);
    if (post_len > 0) {
        post_data[post_len] = '\0';
        int len = mg_get_var(post_data, post_len, name, buf, buf_size);
        if (len > 0) return buf;
    }

    return NULL;
}

static int handle_delete_note(const rpc_request_t* request, rpc_response_t* response) {
    int rc = db_note_delete(request->note_id);
    if (rc != 0) {
        response->status = RPC_ERROR_NOT_FOUND;
        snprintf(response->message, sizeof(response->message), "Failed to delete note");
        return -1;
    }

    response->status = RPC_SUCCESS;
    snprintf(response->message, sizeof(response->message), "Note deleted");
    return 0;
}

int db_note_delete(int note_id) {
    if (g_db == NULL) return -1;

    sqlite3_stmt* stmt;
    int rc = sqlite3_prepare_v2(g_db, DELETE_NOTE, -1, &stmt, NULL);
    if (rc != SQLITE_OK) return -1;

    char timestamp[32];
    get_timestamp(timestamp, sizeof(timestamp));
    sqlite3_bind_text(stmt, 1, timestamp, -1, NULL);
    sqlite3_bind_int(stmt, 2, note_id);

    rc = sqlite3_step(stmt);
    sqlite3_finalize(stmt);

    return (rc == SQLITE_DONE) ? 0 : -1;
}
